prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?modelId ?org ?orgId WHERE {
  ?model a bboExt:Model .
  ?model bbo:name ?modelName .
  OPTIONAL { ?model tai:normalizedId ?modelId . }
  OPTIONAL { ?model tai:originalId ?originalId . }
  OPTIONAL { ?model tai:belongsTo ?org . }
  OPTIONAL { ?org tai:organizationId ?orgId . }
  FILTER(CONTAINS(STR(?modelId), "1ad939") || CONTAINS(STR(?originalId), "1ad939"))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?modelId ?originalId WHERE {
  ?model a bboExt:Model .
  ?model bbo:name ?modelName .
  OPTIONAL { ?model tai:normalizedId ?modelId . }
  OPTIONAL { ?model tai:originalId ?originalId . }
  FILTER(CONTAINS(STR(?modelId), "1ad939") || CONTAINS(STR(?originalId), "1ad939") || CONTAINS(STR(?model), "1ad939"))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?gateway ?gatewayName ?gatewayType ?gatewayDir WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "1ad939eef40c461dafae27f75a0586d3" .
  ?defs tai:belongsTo ?model .
  ?defs a bboExt:Definitions .
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?defs .
  ?gateway tai:belongsTo ?choreo .
  { ?gateway a bboExt:ParallelGateway . }
  UNION
  { ?gateway a bboExt:ExclusiveGateway . }
  UNION
  { ?gateway a bboExt:EventBasedGateway . }
  OPTIONAL { ?gateway bbo:name ?gatewayName . }
  OPTIONAL { ?gateway a ?gatewayType . }
  OPTIONAL { ?gateway bboExt:gatewayDirection ?gatewayDir . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?event ?eventName ?eventType WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "1ad939eef40c461dafae27f75a0586d3" .
  ?defs tai:belongsTo ?model .
  ?defs a bboExt:Definitions .
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?defs .
  ?event tai:belongsTo ?choreo .
  { ?event a bboExt:StartEvent . }
  UNION
  { ?event a bboExt:EndEvent . }
  OPTIONAL { ?event bbo:name ?eventName . }
  OPTIONAL { ?event a ?eventType . }
}
LIMIT 25
